form:Form.form:Scripts:
		function Ejecutar()
{	

	if(Ctrl('interface').GetCValue() == 'RENATRE')
	{
		var ano3 = Ctrl('p_periodo').GetXValue().substr(0,4);
		var mes3 = Ctrl('p_periodo').GetXValue().substr(4,2);
		var mes2 = str2number(Ctrl('p_periodo').GetXValue().substr(4,2)) - 1; 
		var ano2 = Ctrl('p_periodo').GetXValue().substr(0,4); 
		var mes1 = str2number(Ctrl('p_periodo').GetXValue().substr(4,2)) - 2; 
		var ano1 = Ctrl('p_periodo').GetXValue().substr(0,4); 

		if(mes3 == "01")		
		{
			mes2 = "12";
			ano2 = str2number(ano3) - 1;
			mes1 = "11";
			ano1 = str2number(ano3) - 1;
		}
		else if(mes3 == "02")		
		{			
			mes2 = "01";
			mes1 = "12";
			ano1 = str2number(ano3) - 1;
		}		
		return confirm("Periodos a informar:\n Periodo 1: " + mes1 +"/"+ano1+"\n Periodo 2: "+ mes2+"/"+ano2+"\n Periodo 3: "+ mes3+"/"+ano3+".\n Desea continuar?");		
	}

	return true;

}
